UPDATE public.projects SET last_edited_by = 'ds5577@nyu.edu', updated_at = now(), metadata = COALESCE(metadata,'{}'::jsonb) || '{"planning_priorities": ["Define the behavior to measure?", "Define the behavioral tasks the subject should perform?", "Which data modalities and recording devices to use?", "Which acquisition software and hardware to use to record multiple signals?"], "data_types_collected": ["Neural data (e.g., EEG, MEG, fMRI, ECoG, single-unit recordings)", "Behavioral data (e.g., video recordings, motion capture, eye tracking, gait analysis)", "Cognitive performance data (e.g., reaction times, accuracy, task performance metrics)", "Environmental data (e.g., ambient light, temperature, sound levels)", "Social interaction data (e.g., proximity sensors, communication logs)", "Wearable sensor data (e.g., accelerometers, gyroscopes, smartwatches)"], "use_sensors": ["Intracranial Electrophysiology (single-unit recordings)"], "behavioral_recording_tech": ["Video Recording", "Wearable Sensors", "Acoustic Recording", "Behavioral Coding Software"], "behavioral_brands": "WhiteMatter, Avisoft, Bonsai", "hand_coding_method": "Yes, we watch raw videos and videos with keypoint tracking to identify behaviors that might be of interest for further quantification (e.g. using deep-learning tools or other software packages).", "behaviors_of_interest": ["Locomotion and Movement (for example: walking, running, swimming, climbing, jumping)", "Gait Analysis (for example: stride length, step frequency, limb coordination)", "Vocalizations and Speech (for example: talking, crying, barking, chirping)", "Social Interactions (for example: grooming, play behavior, aggression, mating behavior)", "Exploratory Behavior (for example: novel object interaction, maze navigation, environmental exploration)", "Emotional and Stress Responses (for example: anxiety-related behaviors, fear responses, stress-induced behaviors)", "Physical Activity Levels (for example: activity counts, sedentary behavior, exercise routines)", "Reproductive Behaviors (for example: courtship rituals, nest building, parental care)"], "brain_initiative_standards": ["Neurodata Without Borders (NWB)"], "standards_conversion_tools": ["NeuroConv", "Other"], "conversion_tools_details": "Catalyst Neuro", "standards_lifecycle_stages": ["For publication only. We convert data to standard formats for publication purposes to share the data in compliance with NIH policies."], "neural_data_formats": ["HDF5"], "behavioral_data_formats": ["HDF5", "Matlab"], "ontologies_used": ["Mouse Brain Atlas (e.g., Paxinos and Franklin Mouse Brain Atlas) (a detailed anatomical atlas of the mouse brain)"], "ontologies_usage": "To localize probes and cells in the brain (e.g., using CCF and brain atlases)", "data_management_systems": ["Individuals store and manage their own data", "Shared data storage. Data is stored in a shared location(s).", "Git / GitHub (or other version control software and hosting service)"], "primary_storage": "Local, shared storage (e.g., shared network storage for a lab), Institutional cluster, Community Archive (e.g., NDA, SRA, DANDI, DABI, BIL, NeMO, OpenNeuro, NEMAR, BossDB, etc.)", "data_sync_methods": ["Timestamping (embedding precise timestamps in data streams to align them temporally)", "Trigger Signals (using hardware or software triggers to mark events simultaneously across data streams)", "Event Markers (inserting event markers in data streams during specific events to facilitate alignment)", "Hardware Synchronization (using dedicated hardware devices to synchronize data acquisition systems, such as TTL pulses or synchronization boxes)"], "neural_feature_detection": ["Manual feature identification", "Statistical methods (e.g., identify peaks, thresholds)", "AI-based methods (e.g., DNN, LLM,..)", "Domain-specific software - commercial (e.g., MATLAB toolbox, NeuroExplorer)", "Domain-specific software - open source (e.g., MNE-Python, Open Ephys)"], "behavioral_feature_detection"